import torch

class KNNClassifierTorch:
    def __init__(self, k: int = 3):
        self.k = k
        self.X_train = None
        self.y_train = None

    def fit(self, X: torch.Tensor, y: torch.Tensor) -> None:
        self.X_train = X.float()
        self.y_train = y.long()

    def predict(self, X: torch.Tensor) -> torch.Tensor:
        X = X.float()
        # Vectorized pairwise distances using cdist
        dists = torch.cdist(X, self.X_train)  # (n_test, n_train)

        predictions = []
        for i in range(X.shape[0]):
            _, k_idx = torch.topk(dists[i], self.k, largest=False)
            k_labels = self.y_train[k_idx]
            counts = torch.bincount(k_labels)
            predictions.append(int(torch.argmax(counts).item()))
        return torch.tensor(predictions, dtype=torch.long)
